package entities;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class Musique {
    private Integer id;
    private String genre;
    private String audio;
    private LocalDateTime updatedAt;

    // Relation many-to-many via playlist_musique (loaded by service layer).
    private List<Playlist> playlists = new ArrayList<>();

    public Musique() {
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getGenre() {
        return genre;
    }

    public void setGenre(String genre) {
        this.genre = genre;
    }

    public String getAudio() {
        return audio;
    }

    public void setAudio(String audio) {
        this.audio = audio;
    }

    public LocalDateTime getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(LocalDateTime updatedAt) {
        this.updatedAt = updatedAt;
    }

    public List<Playlist> getPlaylists() {
        return playlists;
    }

    public void setPlaylists(List<Playlist> playlists) {
        this.playlists = playlists != null ? playlists : new ArrayList<>();
    }
}

package entities;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class Musique extends Oeuvre {
    private String genre;
    private String audio;
    private LocalDateTime updatedAt;

    // Relation many-to-many via playlist_musique (loaded by service layer).
    private List<Playlist> playlists = new ArrayList<>();

    public Musique() {
        super();
        setClasse("musique");
    }

    public String getGenre() {
        return genre;
    }

    public void setGenre(String genre) {
        this.genre = genre;
    }

    public String getAudio() {
        return audio;
    }

    public void setAudio(String audio) {
        this.audio = audio;
    }

    public LocalDateTime getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(LocalDateTime updatedAt) {
        this.updatedAt = updatedAt;
    }

    public List<Playlist> getPlaylists() {
        return playlists;
    }

    public void setPlaylists(List<Playlist> playlists) {
        this.playlists = playlists != null ? playlists : new ArrayList<>();
    }
}

package controllers.amateur;

import entities.Evenement;
import javafx.fxml.FXML;
import javafx.scene.control.Label;
import javafx.scene.image.Image;
import javafx.scene.image.ImageView;

import java.io.ByteArrayInputStream;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

public class EventCardController {

    private static final DateTimeFormatter DATE_FORMATTER = DateTimeFormatter.ofPattern("EEE, dd MMM yyyy HH:mm");

    @FXML
    private ImageView coverImageView;

    @FXML
    private Label categoryBadgeLabel;

    @FXML
    private Label titleLabel;

    @FXML
    private Label dateLabel;

    @FXML
    private Label placeLabel;

    @FXML
    private Label statusLabel;

    @FXML
    private Label priceLabel;

    @FXML
    private Label descriptionLabel;

    public void setData(Evenement evenement) {
        categoryBadgeLabel.setText(textOrDefault(evenement.getType(), "Evenement"));
        titleLabel.setText(textOrDefault(evenement.getTitre(), "Evenement sans titre"));
        dateLabel.setText(formatDateTime(evenement.getDateDebut()));
        placeLabel.setText(formatCapacity(evenement.getCapaciteMax()));
        statusLabel.setText(textOrDefault(evenement.getStatut(), "A venir"));
        priceLabel.setText(formatPrice(evenement.getPrixTicket()));
        descriptionLabel.setText(textOrDefault(evenement.getDescription(), ""));
        applyImage(evenement.getImageCouverture());
    }

    private void applyImage(byte[] imageBytes) {
        if (imageBytes == null || imageBytes.length == 0) {
            coverImageView.setImage(null);
            return;
        }
        try {
            Image image = new Image(new ByteArrayInputStream(imageBytes));
            coverImageView.setImage(image.isError() ? null : image);
        } catch (Exception e) {
            coverImageView.setImage(null);
        }
    }

    private String formatDateTime(LocalDateTime dateTime) {
        return dateTime == null ? "Date non definie" : DATE_FORMATTER.format(dateTime);
    }

    private String formatCapacity(Integer capacity) {
        return capacity == null ? "Capacite non definie" : capacity + " places";
    }

    private String formatPrice(Double price) {
        return price == null ? "Prix non defini" : String.format("%.0f TND", price);
    }

    private String textOrDefault(String value, String fallback) {
        return value == null || value.isBlank() ? fallback : value;
    }
}

package controllers.amateur;

import entities.Evenement;
import javafx.fxml.FXML;
import javafx.fxml.FXMLLoader;
import javafx.scene.Parent;
import javafx.scene.control.Label;
import javafx.scene.control.TextField;
import javafx.scene.control.ToggleButton;
import javafx.scene.layout.FlowPane;
import services.EvenementService;

import java.io.IOException;
import java.sql.SQLDataException;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.Objects;
import java.util.stream.Collectors;

import controllers.amateur.EventCardController;

public class EventsfrontController {

	@FXML
	private TextField searchField;

	@FXML
	private ToggleButton allTabButton;

	@FXML
	private ToggleButton expositionTabButton;

	@FXML
	private ToggleButton concertTabButton;

	@FXML
	private ToggleButton spectacleTabButton;

	@FXML
	private ToggleButton conferenceTabButton;

	@FXML
	private FlowPane eventsFlowPane;

	@FXML
	private Label emptyStateLabel;

	private final EvenementService evenementService = new EvenementService();
	private final List<Evenement> allEvents = new ArrayList<>();
	private String selectedCategory = "Tous";

	@FXML
	public void initialize() {
		refreshEvents();
		onAllTabClick();
	}

	@FXML
	private void onSearchClick() {
		applyFilters();
	}

	@FXML
	private void onAllTabClick() {
		selectedCategory = "Tous";
		setActiveTab(allTabButton);
		applyFilters();
	}

	@FXML
	private void onExpositionTabClick() {
		selectedCategory = "Exposition";
		setActiveTab(expositionTabButton);
		applyFilters();
	}

	@FXML
	private void onConcertTabClick() {
		selectedCategory = "Concert";
		setActiveTab(concertTabButton);
		applyFilters();
	}

	@FXML
	private void onSpectacleTabClick() {
		selectedCategory = "Spectacle";
		setActiveTab(spectacleTabButton);
		applyFilters();
	}

	@FXML
	private void onConferenceTabClick() {
		selectedCategory = "Conférence";
		setActiveTab(conferenceTabButton);
		applyFilters();
	}

	private void refreshEvents() {
		try {
			allEvents.clear();
			allEvents.addAll(evenementService.getAll());
			allEvents.sort(Comparator.comparing(Evenement::getDateDebut, Comparator.nullsLast(Comparator.naturalOrder())).reversed());
		} catch (SQLDataException e) {
			emptyStateLabel.setText("Impossible de charger les evenements.");
			emptyStateLabel.setVisible(true);
			emptyStateLabel.setManaged(true);
		}
	}

	private void applyFilters() {
		String search = searchField.getText() == null ? "" : searchField.getText().trim().toLowerCase();

		List<Evenement> filtered = allEvents.stream()
				.filter(event -> matchesCategory(event, selectedCategory))
				.filter(event -> matchesSearch(event, search))
				.collect(Collectors.toList());

		renderCards(filtered);
	}

	private boolean matchesCategory(Evenement event, String category) {
		if (category == null || "Tous".equalsIgnoreCase(category)) {
			return true;
		}
		return category.equalsIgnoreCase(safe(event.getType()));
	}

	private boolean matchesSearch(Evenement event, String search) {
		if (search.isEmpty()) {
			return true;
		}

		return contains(event.getTitre(), search)
				|| contains(event.getDescription(), search)
				|| contains(event.getType(), search)
				|| contains(event.getStatut(), search)
				|| contains(event.getPrixTicket() == null ? null : String.valueOf(event.getPrixTicket()), search);
	}

	private void renderCards(List<Evenement> events) {
		eventsFlowPane.getChildren().clear();

		for (Evenement event : events) {
			try {
				FXMLLoader loader = new FXMLLoader(Objects.requireNonNull(getClass().getResource("/views/amateur/components/event-card.fxml")));
				Parent card = loader.load();
				controllers.amateur.EventCardController controller = loader.getController();
				controller.setData(event);
				eventsFlowPane.getChildren().add(card);
			} catch (IOException e) {
				emptyStateLabel.setText("Erreur lors de l'affichage des evenements.");
				emptyStateLabel.setVisible(true);
				emptyStateLabel.setManaged(true);
				return;
			}
		}

		boolean empty = events.isEmpty();
		emptyStateLabel.setVisible(empty);
		emptyStateLabel.setManaged(empty);
	}

	private void setActiveTab(ToggleButton activeButton) {
		ToggleButton[] buttons = {allTabButton, expositionTabButton, concertTabButton, spectacleTabButton, conferenceTabButton};
		for (ToggleButton button : buttons) {
			if (button != null) {
				button.getStyleClass().remove("active");
				button.setSelected(false);
			}
		}
		if (activeButton != null) {
			activeButton.getStyleClass().add("active");
			activeButton.setSelected(true);
		}
	}

	private boolean contains(String value, String search) {
		return value != null && value.toLowerCase().contains(search);
	}

	private String safe(String value) {
		return value == null ? "" : value;
	}
}

package controllers.amateur;

import javafx.fxml.FXML;
import javafx.scene.control.Button;
import javafx.scene.layout.HBox;

import java.util.function.Consumer;

public class MiniAudioPlayerController {

    @FXML
    private HBox playerBar;

    @FXML
    private Button togglePlayButton;

    private Consumer<String> navigationHandler;
    private boolean playing;

    @FXML
    public void initialize() {
        playerBar.setVisible(false);
        playerBar.setManaged(false);
    }

    public void setNavigationHandler(Consumer<String> navigationHandler) {
        this.navigationHandler = navigationHandler;
    }

    public void setVisibleForRoute(String route) {
        boolean isMusicPage = "musique".equals(route);
        playerBar.setVisible(!isMusicPage);
        playerBar.setManaged(!isMusicPage);
    }

    @FXML
    private void onTogglePlay() {
        playing = !playing;
        togglePlayButton.setText(playing ? "||" : ">");
    }

    @FXML
    private void onPrevTrack() {
        // Placeholder for queue previous action.
    }

    @FXML
    private void onNextTrack() {
        // Placeholder for queue next action.
    }

    @FXML
    private void onOpenMusic() {
        if (navigationHandler != null) {
            navigationHandler.accept("musique");
        }
    }
}

package entities;

import java.time.LocalDate;
import java.time.LocalDateTime;

public class Personne {
    private Integer id;
    private String photoProfil;
    private String resetToken;
    private LocalDateTime resetTokenExpires;
    private String nom;
    private String prenom;
    private LocalDate dateNaissance;
    private String email;
    private String mdp;
    private String role;
    private String statut;
    private LocalDate dateInscription;
    private String numTel;
    private String ville;
    private String biographie;
    private String specialite;
    private String centreInteret;
    private String photoReferencePath;

    // Legacy field kept for compatibility with existing ServicePersonne.
    private Integer age;

    public Personne() {
    }

    public Personne(String nom, String prenom, Integer age) {
        this.nom = nom;
        this.prenom = prenom;
        this.age = age;
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getPhotoProfil() {
        return photoProfil;
    }

    public void setPhotoProfil(String photoProfil) {
        this.photoProfil = photoProfil;
    }

    public String getResetToken() {
        return resetToken;
    }

    public void setResetToken(String resetToken) {
        this.resetToken = resetToken;
    }

    public LocalDateTime getResetTokenExpires() {
        return resetTokenExpires;
    }

    public void setResetTokenExpires(LocalDateTime resetTokenExpires) {
        this.resetTokenExpires = resetTokenExpires;
    }

    public String getNom() {
        return nom;
    }

    public void setNom(String nom) {
        this.nom = nom;
    }

    public String getPrenom() {
        return prenom;
    }

    public void setPrenom(String prenom) {
        this.prenom = prenom;
    }

    public LocalDate getDateNaissance() {
        return dateNaissance;
    }

    public void setDateNaissance(LocalDate dateNaissance) {
        this.dateNaissance = dateNaissance;
    }

    public String getEmail() {
        return email;
    }

    public void setEmail(String email) {
        this.email = email;
    }

    public String getMdp() {
        return mdp;
    }

    public void setMdp(String mdp) {
        this.mdp = mdp;
    }

    public String getRole() {
        return role;
    }

    public void setRole(String role) {
        this.role = role;
    }

    public String getStatut() {
        return statut;
    }

    public void setStatut(String statut) {
        this.statut = statut;
    }

    public LocalDate getDateInscription() {
        return dateInscription;
    }

    public void setDateInscription(LocalDate dateInscription) {
        this.dateInscription = dateInscription;
    }

    public String getNumTel() {
        return numTel;
    }

    public void setNumTel(String numTel) {
        this.numTel = numTel;
    }

    public String getVille() {
        return ville;
    }

    public void setVille(String ville) {
        this.ville = ville;
    }

    public String getBiographie() {
        return biographie;
    }

    public void setBiographie(String biographie) {
        this.biographie = biographie;
    }

    public String getSpecialite() {
        return specialite;
    }

    public void setSpecialite(String specialite) {
        this.specialite = specialite;
    }

    public String getCentreInteret() {
        return centreInteret;
    }

    public void setCentreInteret(String centreInteret) {
        this.centreInteret = centreInteret;
    }

    public String getPhotoReferencePath() {
        return photoReferencePath;
    }

    public void setPhotoReferencePath(String photoReferencePath) {
        this.photoReferencePath = photoReferencePath;
    }

    public Integer getAge() {
        return age;
    }

    public void setAge(Integer age) {
        this.age = age;
    }

    @Override
    public String toString() {
        return "Personne{" +
                "id=" + id +
                ", nom='" + nom + '\'' +
                ", prenom='" + prenom + '\'' +
                ", email='" + email + '\'' +
                ", role='" + role + '\'' +
                ", statut='" + statut + '\'' +
                '}';
    }
}

