}

.amateur-root.dark-mode .page-subtitle,
.amateur-root.dark-mode .sidebar-role,
.amateur-root.dark-mode .sidebar-bio,
.amateur-root.dark-mode .sidebar-stat-label,
.amateur-root.dark-mode .sidebar-copyright {
    -fx-text-fill: #b7c4dc;
}
